		for i, v := range unserved {
			if v == bestCandidate.idx {
				unserved[i] = unserved[len(unserved)-1]
				unserved = unserved[:len(unserved)-1]
				break
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch
}
